};

// CCTNS 2.0: Stepper component in React with contextual guides & fields validation
const FIRRegistrationWizard = () => {
  const [step, setStep] = useState(1);
  return (
    <div className="stepper-container">
      <div className="step-indicators">
        <span className={step >= 1 ? "active" : ""}>Complainant Info</span>
        <span className={step >= 2 ? "active" : ""}>Incident Details</span>
        <span className={step >= 3 ? "active" : ""}>Accused Details</span>
      </div>
      {step === 1 && <ComplainantForm onNext={() => setStep(2)} />}
      {step === 2 && <IncidentDetailsForm onNext={() => setStep(3)} />}
      {step === 3 && <AccusedForm onSubmit={submitFIR} />}
    </div>
  );
};

// CCTNS 2.0: Cryptographically linked immutable ledger audit trail
const createAuditLog = async (userId, action, recordId, previousHash) => {
  const timestamp = new Date().toISOString();
  const payload = `${userId}|${action}|${recordId}|${timestamp}|${previousHash}`;

  // Calculate SHA-256 hash
  const currentHash = crypto.createHash('sha256').update(payload).digest('hex');

  const logEntry = new AuditLogModel({
    userId, action, recordId, timestamp, previousHash, currentHash
  });
  await logEntry.save(); // Tampering can be immediately detected if chain breaks
};
